let raw = '';
try {
  raw = $json.choices?.[0]?.message?.content || '{}';
  raw = raw.replace(/```json|```/g, '').trim();
} catch (e) {
  raw = '{}';
}
let decision;
try {
  decision = JSON.parse(raw);
} catch (e) {
  decision = { intent: 'general_chat', confidence: 1.0, params: {} };
}
const VALID_INTENTS = ['general_chat','youtube_search','youtube_download','drive_list','drive_search','drive_upload','drive_download','drive_delete','gmail_search','gmail_read','gmail_send','gmail_delete','calendar_list','calendar_create','calendar_delete','translate','contacts_list','contacts_search','contacts_create','docs_create','docs_read','docs_edit','slides_create','sheets_read','sheets_write','local_screenshot','local_browser','local_app','local_file','local_shell','local_system'];
if (!VALID_INTENTS.includes(decision.intent)) {
  decision.intent = 'general_chat';
  decision.confidence = 0.5;
}
return [{ json: { ...$input.item.json, intent: decision.intent, intentConfidence: decision.confidence || 0, intentParams: decision.params || {} } }];
